ActionEmojiConfig = {}
ActionEmojiConfig.currPersonView = 0

local Config = {}

function ActionEmojiConfig:init(config)
    for _, vConfig in pairs(config) do
        local data = {}
        data.id = tonumber(vConfig.id)
        data.image = tostring(vConfig.image)
        data.name = tostring(vConfig.name)
        Config[tostring(data.id)] = data
    end
end

function ActionEmojiConfig:getConfig(id)
    return Config[tostring(id)]
end

function ActionEmojiConfig:getAllConfig()
    return Config
end

function ActionEmojiConfig:playAction(actionId, name)
    if not isClient then
        return
    end

    ---记录当前视角  镜头距离
    if PlayerManager:getClientPlayer().Player:getPrevUpperAction() ~= 1012 then
        self.currPersonView = Blockman.Instance():getCurrPersonView()
    end
    PlayerManager:getClientPlayer():setPlayerActionName(name)
    PlayerManager:getClientPlayer():setInsertUpperAction1(1012, -1, 0)

    local entityRender = EntityRenderManager.Instance()
    if not entityRender then
        return
    end

    ---同步给其他玩家
    CommonPacketSender:sendUseAction(actionId)

    ---切换至第三人称
    Blockman.Instance():setPersonView(1)
    GUIBedWarSetting:changeCamera(2)
    GUIBedWarToolBar:cameraChange()
    ---相机和玩家分离
    ClientHelper.putBoolPrefs("IsSeparateCamera", true)
    ---拉远镜头
    local thirdPersonDistance = 3

    LuaTimer:cancel(self.breakKey)
    LuaTimer:cancel(self.disKey)
    self.disKey = LuaTimer:scheduleTimer(function()
        thirdPersonDistance = thirdPersonDistance + 0.05
        ClientHelper.putFloatPrefs("ThirdPersonDistance", thirdPersonDistance)
    end, 5, 70)
    ---播放动作

    ---一玩家行动或被攻击后将视角切换回去，并恢复玩家行动能力
    self.breakKey = LuaTimer:scheduleTimer(function()
        if PlayerManager:getClientPlayer().Player:getPrevUpperAction() ~= 1012 then
            LuaTimer:cancel(self.breakKey)
            LuaTimer:cancel(self.disKey)
            Blockman.Instance():setPersonView(self.currPersonView)
            if self.currPersonView == 0 then
                GUIBedWarSetting:changeCamera(1)
            elseif self.currPersonView == 1 then
                GUIBedWarSetting:changeCamera(2)
            elseif self.currPersonView == 2 then
                GUIBedWarSetting:changeCamera(3)
            end

            GUIBedWarToolBar:cameraChange()
            LuaTimer:schedule(function ()
                ClientHelper.putFloatPrefs("ThirdPersonDistance", 0)
                ---相机和玩家分离
                ClientHelper.putBoolPrefs("IsSeparateCamera", false)
            end,1)
        end
    end, 500)
end

ActionEmojiConfig:init(FileUtil.getConfigFromCsv("setting/ActionEmoji.csv"))